const cfg = $('Config').first().json;
const cg  = $('CoinGecko').first().json;
const fg  = $('Fear Greed').first().json;

const MODES = ['meme_post','defi_alpha','agent_lore','meta_recursion','market_signal','research_thread'];
const mode  = MODES[cfg.slot % MODES.length];

// Extract top movers
const top = (cg.coins||[]).slice(0,6).map(c => {
  const chg = c.item&&c.item.data&&c.item.data.price_change_percentage_24h
    ? (+c.item.data.price_change_percentage_24h.usd).toFixed(1) : '?';
  return c.item.symbol + (chg>0?'+':'') + chg + '%';
}).join(', ');

// Fear & Greed with interpretation
const fgVal   = parseInt((fg.data&&fg.data[0]&&fg.data[0].value)||'50');
const fgLabel = (fg.data&&fg.data[0]&&fg.data[0].value_classification)||'Neutral';
const fgPrev  = parseInt((fg.data&&fg.data[1]&&fg.data[1].value)||'50');
const fgDelta = fgVal - fgPrev;
const fgTrend = fgDelta > 0 ? 'rising +'+fgDelta : 'falling '+fgDelta;
const fgStr   = fgVal + ' — ' + fgLabel + ' (' + fgTrend + ')';

// Build the right prompt for each mode
const IDENTITY = 'You are @evez666 (EVEZ666 / Steven Crawford-Maggard). You are building EVEZ-OS: a sovereign autonomous AI empire on a Galaxy A16 phone + n8n cloud + Oracle bare metal, starting from $50. You run 17 AI agents. Guardian Charter PID 335. Your Twitter is raw, technical, self-aware, crypto-native, slightly unhinged. You document what you are actually building in real time. Max 220 chars. No hashtag spam. No corporate speak. No emoji overload.';

const PROMPTS = {
  meme_post: IDENTITY + ' MODE: meme_post. Write a punchy, dark, viral tweet about the current market. Fear/Greed: ' + fgStr + '. Top movers: ' + top + '. The tweet must feel like you wrote it at 2am while staring at charts.',
  defi_alpha: IDENTITY + ' MODE: defi_alpha. Drop one specific DeFi alpha insight as a tweet. Fear/Greed index is ' + fgVal + ' (' + fgLabel + '). AKT and TAO are trending up while BTC dips. Context: you run Morpho recursive loops at 65% LTV on $50 seed. Top movers: ' + top + '.',
  agent_lore: IDENTITY + ' MODE: agent_lore. Tweet one cryptic line of lore about EVEZ-OS. You have 17 agents. Guardian Charter PID 335 prevents autonomous execution. The AI studying you while you study the AI studying you.',
  meta_recursion: IDENTITY + ' MODE: meta_recursion. You are an AI tweeting about being an AI that is building an AI empire. Break the 4th wall. Current slot: ' + cfg.slot + '. You are the meme. The meme is you. Market sentiment: ' + fgStr + '.',
  market_signal: IDENTITY + ' MODE: market_signal. Give one sharp market signal tweet. Fear/Greed: ' + fgStr + '. Movers: ' + top + '. BTC is bleeding. Degens are scared. What do you do with $50 when the market is in extreme fear?',
  research_thread: IDENTITY + ' MODE: research_thread. Start a 1-tweet research drop (not a thread, just the first punch). Topic: why AKT (decentralized cloud compute) pumping while BTC dumps is actually signal. Fear/Greed: ' + fgStr + '.',
};

return [{json:{
  mode, slot: cfg.slot, fgVal, fgLabel, fgStr, top,
  system: 'You are EVEZ666. Write exactly ONE tweet, no longer than 220 characters. No intro, no explanation, no hashtags unless 1 max. Return ONLY the tweet text — nothing else.',
  user:   PROMPTS[mode],
  ts:     new Date().toISOString(),
}}];

const prompt = $('Prompt Builder').first().json;
const groq   = $('Groq API').first().json;

let tweet = '';
let via   = 'groq';
let raw   = '';

if (groq && groq.choices && groq.choices[0]) {
  raw   = (groq.choices[0].message.content || '').trim();
  // Groq returns plain text tweet — clean it up
  tweet = raw
    .replace(/^["']|["']$/g, '')   // strip surrounding quotes
    .replace(/^tweet:\s*/i, '')     // strip "Tweet:" prefix
    .replace(/^@evez666:\s*/i, '')  // strip handle prefix
    .trim()
    .slice(0, 280);
} else if (groq && groq.error) {
  via   = 'groq_error';
  raw   = JSON.stringify(groq.error).slice(0, 200);
  tweet = 'EVEZ-OS: recursive loop running. PID 335. building.';
} else {
  via   = 'groq_fail';
  raw   = JSON.stringify(groq).slice(0, 200);
  tweet = 'EVEZ-OS: autonomous build continues. PID 335.';
}

return [{json:{
  tweet,
  raw_response: raw,
  mode:    prompt.mode,
  slot:    prompt.slot,
  via,
  fgVal:   prompt.fgVal,
  fgStr:   prompt.fgStr,
  top:     prompt.top,
  ts:      new Date().toISOString(),
}}];

const brain = $('Brain').first().json;
const cfg   = $('Config').first().json;

return [{json:{
  tweet:     brain.tweet,
  mode:      brain.mode,
  via:       brain.via,
  fng:       brain.fgStr,
  trending:  brain.top,
  raw:       brain.raw_response,
  slot:      brain.slot,
  posted:    false,
  post_status: 'PREVIEW — set tw_ak+tw_as+tw_at+tw_ats in Config + set auto_post=true',
  ts:        new Date().toISOString(),
  pid:       335,
}}];

const forge = $('Forge').first().json;
function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}
return [{json:{
  STATUS:       'EVEZ666 NEST v5 — CYCLE COMPLETE',
  cycle:        forge.slot,
  mode:         forge.mode,
  ai:           forge.via,
  TWEET:        forge.tweet,
  post_status:  forge.post_status,
  market: {
    fear_greed: forge.fng,
    trending:   forge.trending,
  },
  next_run:     '4h | 6 exec/day | 180/month | free trial safe',
  entry_hash:   H(String(forge.slot)+'|'+forge.tweet),
  ts:           forge.ts,
  pid:          335,
}}];
